patterns.template:
func $NAME(c *gin.Context) {
	$BODY
}

func (h *$HANDLER) $NAME(c *gin.Context) {
	$BODY
}

c.JSON(http.StatusOK, gin.H{
	"$KEY": $VALUE,
})

var $REQUEST $REQUEST_TYPE
if err := c.ShouldBindJSON(&$REQUEST); err != nil {
	c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
	return
}

var $URI struct {
	$PARAM $TYPE `uri:"$PARAM_NAME" binding:"required"`
}
if err := c.ShouldBindUri(&$URI); err != nil {
	c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
	return
}

var $QUERY struct {
	$PARAM $TYPE `form:"$PARAM_NAME"`
}
if err := c.ShouldBindQuery(&$QUERY); err != nil {
	c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
	return
}

func $NAME() gin.HandlerFunc {
	return func(c *gin.Context) {
		// Before request
		$BEFORE

		c.Next()

		// After request
		$AFTER
	}
}

func AuthMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		token := c.GetHeader("Authorization")
		if token == "" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "missing authorization header"})
			return
		}

		// Validate token
		$USER, err := $VALIDATE_TOKEN(token)
		if err != nil {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "invalid token"})
			return
		}

		c.Set("user", $USER)
		c.Next()
	}
}

$GROUP := $ROUTER.Group("/$PREFIX")
{
	$GROUP.GET("/$PATH", $HANDLER)
	$GROUP.POST("/$PATH", $HANDLER)
}

$GROUP := $ROUTER.Group("/$PREFIX")
$GROUP.Use($MIDDLEWARE())
{
	$GROUP.GET("/$PATH", $HANDLER)
	$GROUP.POST("/$PATH", $HANDLER)
}

if err != nil {
	c.AbortWithStatusJSON(http.StatusInternalServerError, gin.H{
		"error": "$MESSAGE",
		"details": err.Error(),
	})
	return
}

$VALUE, exists := c.Get("$KEY")
if !exists {
	c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "$KEY not found in context"})
	return
}
$TYPED := $VALUE.($TYPE)

type $NAME struct {
	$SERVICE *$SERVICE_TYPE
}

func New$NAME($SERVICE *$SERVICE_TYPE) *$NAME {
	return &$NAME{
		$SERVICE: $SERVICE,
	}
}

type $RESOURCE_Handler struct {
	service *$RESOURCE_Service
}

func New$RESOURCE_Handler(service *$RESOURCE_Service) *$RESOURCE_Handler {
	return &$RESOURCE_Handler{service: service}
}

func (h *$RESOURCE_Handler) List(c *gin.Context) {
	items, err := h.service.List(c.Request.Context())
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}
	c.JSON(http.StatusOK, items)
}

func (h *$RESOURCE_Handler) Get(c *gin.Context) {
	id := c.Param("id")
	item, err := h.service.Get(c.Request.Context(), id)
	if err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "not found"})
		return
	}
	c.JSON(http.StatusOK, item)
}

func (h *$RESOURCE_Handler) Create(c *gin.Context) {
	var req $CREATE_REQUEST
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}
	item, err := h.service.Create(c.Request.Context(), &req)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}
	c.JSON(http.StatusCreated, item)
}

func (h *$RESOURCE_Handler) Update(c *gin.Context) {
	id := c.Param("id")
	var req $UPDATE_REQUEST
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}
	item, err := h.service.Update(c.Request.Context(), id, &req)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}
	c.JSON(http.StatusOK, item)
}

func (h *$RESOURCE_Handler) Delete(c *gin.Context) {
	id := c.Param("id")
	if err := h.service.Delete(c.Request.Context(), id); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}
	c.JSON(http.StatusNoContent, nil)
}

func (h *$HANDLER) RegisterRoutes(rg *gin.RouterGroup) {
	$RESOURCES := rg.Group("/$RESOURCE")
	{
		$RESOURCES.GET("", h.List)
		$RESOURCES.GET("/:id", h.Get)
		$RESOURCES.POST("", h.Create)
		$RESOURCES.PUT("/:id", h.Update)
		$RESOURCES.DELETE("/:id", h.Delete)
	}
}

if err := c.ShouldBindJSON(&$REQUEST); err != nil {
	var ve validator.ValidationErrors
	if errors.As(err, &ve) {
		out := make([]gin.H, len(ve))
		for i, fe := range ve {
			out[i] = gin.H{
				"field":   fe.Field(),
				"message": fe.Error(),
			}
		}
		c.JSON(http.StatusBadRequest, gin.H{"errors": out})
		return
	}
	c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
	return
}

func CustomRecovery() gin.HandlerFunc {
	return func(c *gin.Context) {
		defer func() {
			if err := recover(); err != nil {
				log.Printf("panic recovered: %v", err)
				c.AbortWithStatusJSON(http.StatusInternalServerError, gin.H{
					"error": "internal server error",
				})
			}
		}()
		c.Next()
	}
}

func CORSMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		c.Writer.Header().Set("Access-Control-Allow-Origin", "$ORIGIN")
		c.Writer.Header().Set("Access-Control-Allow-Credentials", "true")
		c.Writer.Header().Set("Access-Control-Allow-Headers", "Content-Type, Authorization")
		c.Writer.Header().Set("Access-Control-Allow-Methods", "GET, POST, PUT, DELETE, OPTIONS")

		if c.Request.Method == "OPTIONS" {
			c.AbortWithStatus(http.StatusNoContent)
			return
		}

		c.Next()
	}
}

func LoggingMiddleware(logger *$LOGGER) gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		path := c.Request.URL.Path

		c.Next()

		latency := time.Since(start)
		logger.Info("request",
			"method", c.Request.Method,
			"path", path,
			"status", c.Writer.Status(),
			"latency", latency,
		)
	}
}
